// Filtrar solo PDFs no procesados aún
const items = $input.all();
const files = items[0]?.json || [];

// Si la respuesta viene como array directo
const fileList = Array.isArray(files) ? files : (files.data || []);

// Filtrar: solo PDFs que NO empiecen con '.' (system files)
const pdfs = fileList.filter(f => {
  const name = f.name || '';
  return name.toLowerCase().endsWith('.pdf') && !name.startsWith('.');
});

if (pdfs.length === 0) {
  throw new Error('No se encontraron PDFs en el bucket');
}

// Retornar cada PDF como item separado
return pdfs.map(pdf => ({
  json: {
    file_name: pdf.name,
    file_id: pdf.id || pdf.name,
    bucket: 'ddna-repositorio',
    created_at: pdf.created_at || pdf.metadata?.lastModified
  }
}));

// 📝 NOTA: Para evitar reprocesar PDFs ya indexados, podrías
// consultar la tabla repositorio y filtrar los que tengan processed=true

// Chunk text into ~500 token chunks with 20% overlap
// Estrategia: romper en boundaries naturales (párrafos, oraciones)

const items = $input.all();
const results = [];

for (const item of items) {
  const text = item.json.text || item.json.content || '';
  const source = item.json.source || item.json.fileName || $('Loop Each File').first().json.file_name || 'unknown';
  const fileId = $('Loop Each File').first().json.file_id || source;

  // 500 tokens ≈ 2000 caracteres (aproximación español)
  const MAX_CHARS = 2000;
  const OVERLAP_CHARS = Math.floor(MAX_CHARS * 0.2); // 400 chars = 20%

  if (!text || text.length < 50) {
    // Texto muy corto — un solo chunk
    if (text && text.trim().length > 0) {
      results.push({
        json: {
          repo_file_id: fileId,
          chunk_index: 0,
          content: text.trim(),
          source: source,
          file_type: 'pdf',
          char_count: text.trim().length,
          word_count: text.trim().split(/\s+/).length,
          processed_at: new Date().toISOString()
        }
      });
    }
    continue;
  }

  let chunkIndex = 0;
  let start = 0;

  while (start < text.length) {
    let end = start + MAX_CHARS;

    if (end < text.length) {
      // Intentar cortar en salto de párrafo
      const window = text.slice(start, end);
      const paraBreak = window.lastIndexOf('\n\n');
      const sentenceBreak = window.lastIndexOf('. ');

      // Preferir corte en párrafo si está en la segunda mitad del chunk
      if (paraBreak > MAX_CHARS * 0.4) {
        end = start + paraBreak;
      } else if (sentenceBreak > MAX_CHARS * 0.4) {
        end = start + sentenceBreak + 1;
      }
    } else {
      end = text.length;
    }

    const chunkText = text.slice(start, end).trim();
    if (chunkText.length > 30) {
      results.push({
        json: {
          repo_file_id: fileId,
          chunk_index: chunkIndex,
          content: chunkText,
          source: source,
          file_type: 'pdf',
          char_count: chunkText.length,
          word_count: chunkText.split(/\s+/).length,
          processed_at: new Date().toISOString()
        }
      });
      chunkIndex++;
    }

    start = end - OVERLAP_CHARS;
    if (start >= text.length - 10) break;
  }
}

return results;

// Formatear para insertar en doc_chunks
const items = $input.all();

return items.map((item, i) => {
  const prevItem = $('Chunk Text').all()[i] || {};
  const embedding = item.json.data?.[0]?.embedding || [];

  return {
    json: {
      repo_file_id: prevItem.json?.repo_file_id || '',
      chunk_index: prevItem.json?.chunk_index || 0,
      content: prevItem.json?.content || '',
      embedding: embedding,
      metadata: {
        source: prevItem.json?.source || '',
        type: prevItem.json?.file_type || 'pdf',
        chunk_size: prevItem.json?.word_count || 0,
        processed_at: prevItem.json?.processed_at || new Date().toISOString()
      }
    }
  };
});

// Resumen final: cuántos chunks se procesaron
const allInserts = $('Save to doc_chunks').all();

let totalChunks = 0;
const files = new Set();

for (const ins of allInserts) {
  const body = ins.json.body || ins.json;
  if (body) totalChunks++;
}

return [{
  json: {
    status: 'completed',
    total_chunks: totalChunks,
    message: `Backfill completado: ${totalChunks} chunks indexados`
  }
}];
